/**
 * @method 
 * @name confirmCallback 
 * @description
 */
scwin.confirmCallback = async function (e) {
  if (e.callFnc == 'f_Save') {
    if (!e.clickValue) {
      $c.win.alert($p, e.lineNm + "라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
      return;
    }
    ;
    let retObj = await $c.sbm.execute($p, sbm_createCrryoutIntendInfo);
    if (retObj.responseJSON.resultDataSet[0].Msg == 'SUCC') {
      await scwin.sbm_createCrryoutIntendInfo_submitdone(retObj);
    }
    ;
  }
  ;
};

/**
 * @method 
 * @name f_prefareCheck 
 * @description 행추가전 디폴트값 Check
 */
scwin.f_prefareCheck = function () {
  let firstRowData = ds_onReqInfo.getRowJSON(0);
  if (firstRowData.impExpClsCd == "I" //수입인경우
  && firstRowData.demDt != "" //체선일자가 null이 아닌 경우
  && demDt.getValue() < scwin.strCurDate) {
    //체선일자는 반출예정일자보다 커야 한다.
    $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_005, ["체선일자", "반출예정일"]);
    return false;
  }
  ;
  let totalRow = ds_carryInOutInfo.getTotalRow();
  for (i = 0; i < totalRow; i++) {
    let rowData = ds_carryInOutInfo.getRowJSON(i);
    if (ds_carryInOutInfo.getRowStatus(i) == "3") {
      if (rowData.crryinoutIntendDt == "") {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["상차예정일"]);
        return false;
      }
      ;
      if (rowData.crryinoutIntendHh == "") {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["시간"]);
        return false;
      }
      ;
      if (!dscommon.cf_gidHourCheck(rowData.crryinoutIntendHh) || rowData.crryinoutIntendHh.length < 4) {
        $c.gus.cfAlertMsg($p, scwin.MSG_OP_ERR_001);
        return false;
      }
      ;
      if (rowData.vehclNo == "") {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["차량번호"]);
        return false;
      }
      ;
      if (rowData.vehclIdCardNo == "") {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["차량번호"]);
        return false;
      }
      ;
      if (rowData.drvNm == "") {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["기사명"]);
        return false;
      }
      ;
      if (rowData.drvTelNo == "") {
        $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["연락처"]);
        return false;
      }
      ;
    }
    ;
  }
  ;
  return true;
};

