/**
 * @method 
 * @name f_crryInOutEDI 
 * @description 반출입예정정보EDI등록
 */
scwin.f_crryInOutEDI = async function (bAlertFlag, bSaveFlag, bTransferFlag, row, bDeleteFlag) {
  if (ds_carryInOutInfo.getTotalRow() == 0) return;
  if (ds_carryInOutInfo.getCellData(row, "vehclNo") == "") {
    if (bAlertFlag) {
      $c.gus.cfAlertMsg($p, "운송차량이 없습니다");
    }
    ;
    return false;
  }
  ;

  //저장,전송인경우
  if (bSaveFlag) {
    dma_searchEDI.setEmptyValue();
    let jsonData = {
      "qryClsCd": "1",
      "transWrkIndictNo": ds_retrievePreliminaryInformationEdi.getCellData(row, "scwin.onReqNo"),
      "odrNo": ds_results.getCellData(row, "odrNo"),
      "cntrSeq": ds_results.getCellData(row, "cntrSeq"),
      "wrkPathSeq": ds_results.getCellData(row, "odrWrkPathSeq"),
      "wrkStpSeq": ds_results.getCellData(row, "odrWrkStpSeq"),
      "vehclNo": ds_results.getCellData(row, "vehclNo"),
      "crryinoutDt": ds_results.getCellData(row, "wrkStDt"),
      "crryinDt": ds_results.getCellData(row, "wrkEndDt"),
      "odrNo": ds_results.getCellData(row, "odrNo"),
      "cntrNo": ds_results.getCellData(row, "cntrNo"),
      "dptWrkPlCd": ds_results.getCellData(row, "dptWrkPlCd"),
      "arvWrkPlCd": ds_results.getCellData(row, "arvWrkPlCd"),
      "sndFlag": bTransferFlag == true ? "1" : "0",
      "delFlag": bDeleteFlag == true ? "1" : "0"
    };
    dma_searchEDI.setJSON(jsonData);

    //메시지 표시를 위해 저장(작업완료후 전송, 저장여부를 메시지로 표시해줌)
    gv_bEdiTransfer = bTransferFlag;
    $c.sbm.execute($p, sbm_saveEDI);
    return true;
  }
  ;
  let ediFocusedIdx = ds_retrievePreliminaryInformationEdi.getRowPosition();
  let ediRowData = ds_retrievePreliminaryInformationEdi.getRowJSON(ediFocusedIdx);
  let infoFocusedIdx = ds_carryInOutInfo.getRowPosition();
  let infoRowData = ds_carryInOutInfo.getRowJSON(infoFocusedIdx);
  let arrParam = new Array();
  arrParam[0] = new Array("1",
  //조회구분 ("" : 운송작업지시, "1" : 반출입)
  ediRowData.onReqNo, ediRowData.odrNo, ediRowData.cntrSeq, ediRowData.odrWrkPathSeq, ediRowData.odrWrkStpSeq, infoRowData.vehclNo, infoRowData.vehclNo, infoRowData.vehclIdCardNo, infoRowData.crryinoutIntendDt, infoRowData.crryinoutIntendDt, infoRowData.cntrNo, infoRowData.wrkPlCd, "", infoRowData.wrkPlNm, "", "CO", "N");
  arrParam[1] = new Array(infoRowData.onReqNo, infoRowData.vehclNo, infoRowData.vehclIdCardNo, infoRowData.drvNm, infoRowData.drvTelNo, infoRowData.crryinoutIntendDt, infoRowData.crryinoutIntendHh, "", "");
  await $c.win.openPopup($p, '/ui/ds/op/wrkplan/transwrkplan/op_202_02_21p.xml', {
    popupName: '반출입예정정보EDI등록',
    width: '1100px',
    height: '1080px'
  }, {
    arrParam: arrParam,
    'crryoutEdiType': 'CO',
    'crryinEdiType': 'N'
  });
  scwin.f_RetrieveCrryoutInfo();
  return true;
};

/**
 * @method 
 * @name f_retrievePreliminaryInformationEdi 
 * @description 
 */
scwin.f_retrievePreliminaryInformationEdi = async function () {
  if (!ds_onReqInfo.getTotalRow() > 0) return;

  //현재시간 세팅
  scwin.f_getTime();
  let carryInOutFocusedIdx = ds_carryInOutInfo.getRowPosition();
  let carryInOutRowData = ds_carryInOutInfo.getRowJSON(carryInOutFocusedIdx);
  if (scwin.currTime > "1730" && carryInOutRowData.wrkPlCd == "6C01") {
    $c.win.alert($p, "17시 30분 이후에는 " + carryInOutRowData.wrkPlNm + "의 요청으로 EDI 전송을 할 수 없습니다.");
    return false;
  }
  let focusedIdx = ds_onReqInfo.getRowPosition() ?? 0;
  let rowData = ds_onReqInfo.getRowJSON(focusedIdx);
  let strOdrNo = rowData.odrNo;

  // PRISM OPEN에 의한 SITC, NOLS, SOFC, TCLC라인 코피노전송 막기 (SITC는 수출만 막기), 2014.09.22 TMSC라인 추가
  if (strOdrNo.slice(1, 3) == "C4" && rowData.lineCd == "SITC") {
    $c.win.alert($p, "SITC라인은 PRISM선사이므로 eTRANS에서 전송하세요 .");
    return false;
  }
  ;
  let prismArray = ["NOLS", "SOFC", "TCLC", "TMSC", "TJM", "MAS", "JJS", "DWH", "RHT", "ONE"];
  if (prismArray.includes(rowData.lineCd)) {
    $c.win.alert($p, "NOLS, SOFC, TCLC, TMSC, TJM, MAS, JJS, DWH, RHT, ONE 라인은 PRISM선사이므로 eTRANS에서 전송하세요 .");
    return false;
  }
  ;

  // PRISM OPEN에 의한 SITC, NOLS, SOFC, TCLC라인 코피노전송 막기
  if (strOdrNo.slice(1, 3) == "C2") {
    switch (rowData.lineCd) {
      case "TSL":
      case "EAS":
      case "PAN":
      case "SITC":
      case "GBH":
      case "KYW":
      case "COHAPL":
      case "YNK":
      case "COS":
      case "MOL":
      case "SWIL":
        let lineNm = rowData.lineCd;
        if (rowData.lineCd == 'PAN') lineNm = 'PANSTAR';
        $c.win.alert($p, lineNm + "라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
        return false;
      default:
        break;
    }
    ;
  }
  ;
  if (["APL", "SKR"].includes(rowData.lineCd)) {
    $c.win.alert($p, rowData.lineCd + "라인 반출입처리는 KLNET통하여  처리하세요!!!");
    return false;
  }
  ;
  if (carryInOutRowData.crryinEdiFlag1 == '' && carryInOutRowData.crryinCyFlag == '') {
    $c.win.alert($p, "반출입 예정 정보 등록을 하신후 반출입예정정보(COPINO EDI)등록을 하세요");
    return;
  }
  ;
  if (carryInOutRowData.crryinoutPrgsStsNm == '대기') {
    $c.win.alert($p, "반출입 예정 정보 등록을 하신후 반출입예정정보(COPINO EDI)등록을 하세요");
    return;
  }
  ;

  //KBCTCY에서 수출자가운송 반출예정정보 등록시 COPINO EDI 전송못하도록 함
  //김성지 대리 요청
  if (carryInOutRowData.wrkPlCd == "6C01" && (strOdrNo.slice(1, 3) == "C4" || strOdrNo.slice(1, 3) == "C6")) {
    $c.win.alert($p, "상차지가 " + carryInOutRowData.wrkPlNm + "인 경우 담당자가  COPINO EDI를 전송합니다.");
    return;
  }
  ;
  let strOdrNos = rowData.odrNo;
  if (strOdrNos.slice(1, 3) == "C2") {
    //C2오더일때
    // 현위치와 하선지가 다른경우
    if (carryInOutRowData.currPosCd != carryInOutRowData.arvWrkPlCd) {
      $c.win.alert($p, "직반출 건이 아닙니다. 담당자에게 확인하세요." + "[" + carryInOutRowData.currPosCd + ":" + carryInOutRowData.arvWrkPlCd + "]");
      return;
    }
    ;
  }
  ;
  jsonData = {
    "selfTransClntNo": carryInOutRowData.selfTransClntNo,
    "onReqNo": carryInOutRowData.onReqNo,
    "cntrNo": carryInOutRowData.cntrNo,
    "impExpClsCd": carryInOutRowData.impExpClsCd,
    "cntrDsgYn": carryInOutRowData.cntrDsgYn,
    "wrkPlCd": carryInOutRowData.wrkPlCd,
    "gubun": carryInOutRowData.gubun,
    "cntrSeq": carryInOutRowData.cntrSeq
  };
  dma_condition.setJSON(jsonData);
  let retObj = await $c.sbm.execute($p, sbm_retrievePreliminaryInformationEdi);
  if (retObj.responseJSON.resultDataSet[0].Msg == 'SUCC') {
    await scwin.sbm_retrievePreliminaryInformationEdi_submitdone(retObj);
  }
  ;
};

/**
 * @method 
 * @name f_OzReport 
 * @description 발행 
 */
scwin.f_OzReport = async function () {
  if (scwin.strCurDate < "20110822") {
    $c.win.alert($p, "상차증발행은 2011년 8월 22일부터 사용할 수 있습니다.");
    return false;
  }
  ;

  // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
  let check = 0;
  let crryinoutIntendNo = "";
  let printYn = 0;
  let rowCnt = ds_carryInOutInfo.getTotalRow();
  let rowData = null;
  for (let i = 0; i < rowCnt; i++) {
    rowData = ds_carryInOutInfo.getRowJSON(i);
    if (rowData.chk == 1) {
      //검색어 세팅
      dma_printYnCondition.set("selfTransClntNo", rowData.selfTransClntNo);
      dma_printYnCondition.set("onReqNo", rowData.scwin.onReqNo);
      dma_printYnCondition.set("onReqGoodsSeq", rowData.onReqGoodsSeq);
      dma_printYnCondition.set("printYn", 1);
      crryinoutIntendNo = rowData.crryinoutIntendNo;
      printYn = rowData.printYn;
    } else {
      check++;
    }
    ;
  }
  ;
  if (rowCnt == check) {
    $c.win.alert($p, "상차증을 발행할 컨테이너를 선택하세요.");
    return false;
  }
  ;
  if (crryinoutIntendNo == "") {
    $c.win.alert($p, "선택된 컨테이너는 예정정보를 먼저 등록하신 후에 상차증을 발행할 수 있습니다.");
    return false;
  }
  ;
  if (printYn >= 1) {
    $c.win.alert($p, "선택된 컨테이너는 이미 상차증이 발행되었습니다.\n추가 발행을 원하시면 담당자에게 문의하세요.");
    return false;
  }
  ;

  //update
  $c.sbm.execute($p, sbm_updatePrintYn);
  let ozrId = "/ds/op/wrkrslts/cywrkrslts/op_301_02_21r.ozr";
  let odiId = "op_301_02_21r";

  // OZ리포트
  const data = {
    reportName: ozrId,
    // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
    odiParam: {
      'sysPath': 'dbl.ds.op.wrkrslts.cywrkrslts',
      'crryinoutIntendNo': crryinoutIntendNo
    },
    // OZ 뷰어에 대한 설정(상세 설정은 'oz report viewer guide.pdf'를 참조)
    viewerParam: {
      'useprogressbar': 'false'
    },
    // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
    formParam: {}
  };
  let options = {
    id: "ozReportPopup",
    popupName: "오즈 리포트",
    modal: true,
    type: "browserPopup",
    width: 1000,
    height: 600,
    title: "오즈 리포트"
  };
  await $c.win.openPopup($p, "/ui/cm/zz/ozreportPopup.xml", options, data);
  scwin.f_RetrieveCrryoutInfo();
};

